  &quot;aggs&quot;: {
    &quot;significant_words&quot;: {
      &quot;significant_terms&quot;: {
        &quot;field&quot;:  &quot;suggest_word_all&quot;,
        &quot;min_doc_count&quot;: 1,
        &quot;include&quot;: q+&#039;.*&#039;
      }
    },
    &quot;significant_phrases&quot;: {
      &quot;terms&quot;: {
        &quot;field&quot;:  &quot;suggest_phrase&quot;,
        &quot;order&quot;:  { &quot;_count&quot;: &quot;desc&quot; },
        &quot;include&quot;: q+&#039;.*&#039;,
        &quot;min_doc_count&quot;: 1
      }
    }
  },
  ...
}
